17.query:
timeseries sum(github.actions.workflows), filter: { matchesValue(github.repository.name, $Repository) and matchesValue(github.actions.event.ref.name, $Branch) }
| fieldsAdd github.actions.workflows = "sum(github.actions.workflows)"
| fieldsAdd value.A = toLong(arraySum(`sum(github.actions.workflows)`))

